// TestFlagNotFound tests handling of non-existent flags
func TestFlagNotFound(t *testing.T) {
	store := newMockFlagStore()
	// Don't add any flags to the store

	grpcServer, grpcAddr := setupEvaluationServer(t, store)
	defer grpcServer.Stop()

	httpServer := setupGatewayHTTPServer(t, grpcAddr)
	defer httpServer.Close()

	reqBody := map[string]interface{}{
		"namespace_key": "default",
		"flag_key":      "nonexistent_flag",
		"entity_id":     "user999",
	}

	body, err := json.Marshal(reqBody)
	require.NoError(t, err)

	resp, err := http.Post(
		fmt.Sprintf("%s/evaluate/v1/boolean", httpServer.URL),
		"application/json",
		bytes.NewReader(body),
	)
	require.NoError(t, err)
	defer resp.Body.Close()

	// Should return an error status code for not found
	if resp.StatusCode == http.StatusOK {
		t.Fatalf("expected non-200 status for nonexistent flag, got %d", resp.StatusCode)
	}
}

// TestInvalidRequestBody tests handling of invalid request bodies
func TestInvalidRequestBody(t *testing.T) {
	store := newMockFlagStore()
	grpcServer, grpcAddr := setupEvaluationServer(t, store)
	defer grpcServer.Stop()

	httpServer := setupGatewayHTTPServer(t, grpcAddr)
	defer httpServer.Close()

	// Send invalid JSON
	resp, err := http.Post(
		fmt.Sprintf("%s/evaluate/v1/boolean", httpServer.URL),
		"application/json",
		bytes.NewReader([]byte("invalid json {{{{")),
	)
	require.NoError(t, err)
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusBadRequest {
		t.Fatalf("expected status 400 for invalid JSON, got %d", resp.StatusCode)
	}
}

// TestBatchEvaluation tests batch evaluation endpoint
func TestBatchEvaluation(t *testing.T) {
	store := newMockFlagStore()
	store.flags["default:flag1"] = &flipt.Flag{
		NamespaceKey: "default",
		Key:          "flag1",
		Type:         flipt.FlagType_BOOLEAN_FLAG_TYPE,
		Enabled:      true,
	}
	store.flags["default:flag2"] = &flipt.Flag{
		NamespaceKey: "default",
		Key:          "flag2",
		Type:         flipt.FlagType_BOOLEAN_FLAG_TYPE,
		Enabled:      false,
	}

	grpcServer, grpcAddr := setupEvaluationServer(t, store)
	defer grpcServer.Stop()

	httpServer := setupGatewayHTTPServer(t, grpcAddr)
	defer httpServer.Close()

	batchReqBody := map[string]interface{}{
		"request_id": "batch-req-123",
		"requests": []map[string]interface{}{
			{
				"namespace_key": "default",
				"flag_key":      "flag1",
				"entity_id":     "user1",
			},
			{
				"namespace_key": "default",
				"flag_key":      "flag2",
				"entity_id":     "user2",
			},
		},
	}

	body, err := json.Marshal(batchReqBody)
	require.NoError(t, err)

	resp, err := http.Post(
		fmt.Sprintf("%s/evaluate/v1/batch", httpServer.URL),
		"application/json",
		bytes.NewReader(body),
	)
	require.NoError(t, err)
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		t.Fatalf("expected status 200 for batch request, got %d", resp.StatusCode)
	}

	var result map[string]interface{}
	err = json.NewDecoder(resp.Body).Decode(&result)
	require.NoError(t, err)

	// Check that we got responses
	responses, ok := result["responses"].([]interface{})
	if !ok || len(responses) != 2 {
		t.Fatalf("expected 2 responses in batch result, got %v", result["responses"])
	}
}

// TestNamespaceScoping tests evaluation with different namespaces
func TestNamespaceScoping(t *testing.T) {
	store := newMockFlagStore()
	store.flags["default:scoped_flag"] = &flipt.Flag{
		NamespaceKey: "default",
		Key:          "scoped_flag",
		Type:         flipt.FlagType_BOOLEAN_FLAG_TYPE,
		Enabled:      true,
	}
	store.flags["custom_ns:scoped_flag"] = &flipt.Flag{
		NamespaceKey: "custom_ns",
		Key:          "scoped_flag",
		Type:         flipt.FlagType_BOOLEAN_FLAG_TYPE,
		Enabled:      false,
	}

	grpcServer, grpcAddr := setupEvaluationServer(t, store)
	defer grpcServer.Stop()

	httpServer := setupGatewayHTTPServer(t, grpcAddr)
	defer httpServer.Close()

	// Test evaluation in default namespace
	reqBody1 := map[string]interface{}{
		"namespace_key": "default",
		"flag_key":      "scoped_flag",
		"entity_id":     "user_a",
	}

	body1, err := json.Marshal(reqBody1)
	require.NoError(t, err)

	resp1, err := http.Post(
		fmt.Sprintf("%s/evaluate/v1/boolean", httpServer.URL),
		"application/json",
		bytes.NewReader(body1),
	)
	require.NoError(t, err)
	defer resp1.Body.Close()

	var result1 map[string]interface{}
	err = json.NewDecoder(resp1.Body).Decode(&result1)
	require.NoError(t, err)

	if result1["enabled"] != true {
		t.Fatalf("expected enabled=true for default namespace flag, got %v", result1["enabled"])
	}

	// Test evaluation in custom namespace
	reqBody2 := map[string]interface{}{
		"namespace_key": "custom_ns",
		"flag_key":      "scoped_flag",
		"entity_id":     "user_b",
	}

	body2, err := json.Marshal(reqBody2)
	require.NoError(t, err)

	resp2, err := http.Post(
		fmt.Sprintf("%s/evaluate/v1/boolean", httpServer.URL),
		"application/json",
		bytes.NewReader(body2),
	)
	require.NoError(t, err)
	defer resp2.Body.Close()

	var result2 map[string]interface{}
	err = json.NewDecoder(resp2.Body).Decode(&result2)
	require.NoError(t, err)

	if result2["enabled"] != false {
		t.Fatalf("expected enabled=false for custom_ns namespace flag, got %v", result2["enabled"])
	}
}

